"""
MKT Original Commentary — Psalms 103–104 (57 verses)
Run: python3 scripts/zc-original-psalms-103-104.py

Key decisions:
- Ps 103: participial string (vv3-5) as YHWH's ongoing actions not past events;
  v8 = verbatim Exod 34:6 citation; spatial metaphors for ḥesed (heavens/earth v11,
  east/west v12) treated as measuring the immeasurable; rāḥam from reḥem
  (womb-compassion, v13); dust-formation (v14 echoing Gen 2:7 / 3:19);
  ʿedî (ornaments, v5) = the soul's dignity restored; threefold bless-ascending
  (soul → angels → armies → all creation → soul returns, vv20-22)
- Ps 104: creation hymn; light as divine clothing (v2, not a created thing but
  YHWH's garment); ʿōśeh malʾākhāyw rûḥôt (v4) deliberately ambiguous — winds
  as angels / angels as wind-messengers; Leviathan formed to play (v26) = the
  radical domestication of the chaos monster (not enemy but creature); rûaḥ
  (Spirit/breath, vv29-30) as the animating principle of all life echoing Gen 1:2;
  hallĕlûyāh at v35 = the Psalter's first occurrence; the one jarring petition
  (sinners vanish) within an otherwise celebratory psalm
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW = {
  "103": {
    "1": "<p><b>bārekî nafshî ʾet-YHWH</b> — <i>bless the LORD, O my soul</i>. The unusual self-address: the Psalmist commands his own <i>nefesh</i> (soul, the animated self in its entirety) to bless (<i>bārak</i>: to kneel before, to honor, to pronounce as blessed) YHWH. The soul must be commanded because blessing can be withheld by inertia or distraction — it requires a deliberate act of will. <b>wĕkhol-qĕrābay ʾet-shēm qodshô</b> — <i>let every part of me bless his holy name!</i> <i>Qĕrāb</i> (inner parts, innermost being — the collective interior of the person) to bless the divine name. Not a vague generality but a claim about the totality of inner life.</p>",
    "2": "<p><b>bārekî nafshî ʾet-YHWH wĕʾal-tishkĕḥî kol-gĕmûlāyw</b> — <i>bless the LORD, O my soul, and forget not a single good thing he has done</i>. The repeated self-command (<i>bārekî nafshî</i>) now joined with its corrective: <i>wĕʾal-tishkĕḥî</i> (and do not forget). Forgetting the divine benefits is the besetting failure of covenant ingratitude (Deut 8:11-14; Ps 78:11). <i>Gĕmûl</i> (benefit, good done — from gāmal: to ripen, to deal fully with; the full, complete good that YHWH has dealt). The psalm's thanksgiving arises from deliberate remembrance.</p>",
    "3": "<p><b>hassōlēaḥ lĕkhol-ʿăwōnekhî</b> — <i>who forgives every one of your sins</i>. <i>Sālaḥ</i> (to forgive — the divine forgiveness; used only of God in the OT, never of human forgiveness of each other). The participle (<i>hassōlēaḥ</i>: the one who is forgiving) indicates ongoing divine activity, not a single past event. <b>hārōphēʾ lĕkhol-taḥălûʾêkhî</b> — <i>who heals every one of your illnesses</i>. <i>Rāphāʾ</i> (to heal — divine healing parallel to divine forgiveness). The pairing of sin-forgiveness and disease-healing is not a mechanical equation (sin causes all illness) but a theological statement: YHWH addresses the whole damaged human condition.</p>",
    "4": "<p><b>haggōʾēl mishshaḥat ḥayyayikh</b> — <i>who redeems your life from the pit</i>. <i>Gāʾal</i> (to redeem — the kinsman-redeemer's action, restoring family members from danger, debt, or death). <i>Shaḥat</i> (the pit/grave — Sheol's concrete image). <b>hameʿaṭṭĕrêkhî ḥesed wĕraḥămîm</b> — <i>who crowns you with steadfast love and compassion</i>. <i>ʿĀṭar</i> (piel: to crown — the placing of a crown on the head). The attributes themselves become the crown: <i>ḥesed</i> (steadfast love) + <i>raḥămîm</i> (compassion — the plural from <i>reḥem</i>: womb; the deep visceral compassion of a parent for a child). The redeemed person wears divine love and compassion as a royal crown.</p>",
    "5": "<p><b>hammaśbîaʿ bĕṭôb ʿedyēkh</b> — <i>who satisfies you with good so that your strength is renewed</i>. <i>Śābaʿ</i> (to satisfy, fill to fullness — the opposite of the emptiness of sin and disease). <i>ʿAdî</i> (ornament, adornment — what is beautiful; the soul's beauty and dignity restored by divine filling). <b>titḥaddēsh kĕnnesher nĕʿûrāyikh</b> — <i>your youth is renewed like the eagle</i>. <i>Nāshar</i> (eagle or vulture — the large raptor known for apparent renewal; possibly the molting of old feathers for new ones, or the long life of the eagle: in ancient tradition the eagle was thought to renew its youth). <i>Nĕʿûrîm</i> (youth, youthfulness). The renewal of youth as the culmination of the participial string: forgiving, healing, redeeming, crowning, satisfying — all together constitute the restoration of the whole person.</p>",
    "6": "<p><b>ʿōśeh ṣĕdāqôt YHWH ûmishpāṭîm lĕkhol-ʿăshûqîm</b> — <i>the LORD acts with righteousness and justice for all who are oppressed</i>. <i>Ṣĕdāqôt</i> (righteous acts — the plural indicating multiple acts of justice). <i>ʿĀshûq</i> (oppressed — passive participle of ʿāshaq: to squeeze/oppress, those crushed by injustice). The movement from the personal (vv1-5: benefits for the individual soul) to the social (v6: justice for the oppressed). YHWH's ḥesed expressed in both personal healing and social justice.</p>",
    "7": "<p><b>yôdîaʿ dĕrākhāyw lĕmōsheh libnê yisrāʾēl ʿalîlôtāyw</b> — <i>he revealed his ways to Moses and his mighty deeds to the people of Israel</i>. <i>Dārakh</i> (ways — the characteristic patterns of divine action) revealed to Moses specifically — the Sinai self-revelation of Exod 33-34, where Moses asked to know God's ways (<i>hôdîʿênî nā ʾet-dĕrākekhā</i>, Exod 33:13). <i>ʿAlîlāh</i> (mighty deed, act — the recorded powerful acts) to the whole people. Moses received the <i>why</i> (the ways); Israel received the <i>what</i> (the acts).</p>",
    "8": "<p><b>raḥûm wĕḥannûn YHWH ʾerek ʾappayim wĕrab-ḥāsed</b> — <i>the LORD is compassionate and gracious, patient in anger and overflowing with steadfast love</i>. The direct citation of the Mosaic self-revelation formula of Exod 34:6 (the <i>middôt</i> — divine attributes). This is the text Moses received when he asked to know God's ways (v7). The four attributes: <i>raḥûm</i> (compassionate — from <i>reḥem</i>: womb), <i>ḥannûn</i> (gracious — giving grace freely), <i>ʾerek ʾappayim</i> (long-nostrilled: slow to anger — the nostril-flaring of rage restrained), <i>rab-ḥesed</i> (great in steadfast love). The most cited divine self-description in the OT (Num 14:18; Neh 9:17; Ps 86:15; 145:8; Joel 2:13; Jon 4:2).</p>",
    "9": "<p><b>lōʾ-lāneṣaḥ yārîb wĕlōʾ lĕʿôlām yiṭṭôr</b> — <i>he does not bring charges forever, nor does he hold on to his anger without end</i>. <i>Rîb</i> (to contend, bring a legal charge — the covenant-lawsuit verb; cf. Ps 50's divine lawsuit). <i>Nāṭar</i> (to keep, maintain — to hold a grudge permanently). The temporally bounded nature of divine anger: <i>lāneṣaḥ</i> (forever) and <i>lĕʿôlām</i> (to the age) both negated. YHWH's anger is real but not eternal — the divine patience eventually resolves in forgiveness, not in permanent prosecution.</p>",
    "10": "<p><b>lōʾ khĕḥăṭāʾênû ʿāśāh lānû wĕlōʾ khăʿăwōnōtênû gāmal ʿālênû</b> — <i>he has not treated us as our sins deserve, nor paid us back measure for measure for our iniquities</i>. The double negation: <i>lōʾ… lōʾ</i> — neither sins-proportional treatment (<i>ḥăṭāʾênû</i>: our sins) nor iniquities-proportional repayment (<i>ʿăwōnōtênû gāmal</i>: our iniquities measured back). <i>Gāmal</i> (to deal fully with, to recompense exactly) — the exact recompense that divine mercy withholds. The psalm does not claim there is no divine judgment but that divine mercy prevents full judicial recompense.</p>",
    "11": "<p><b>kî kigbōaḥ shāmayim ʿal-hāʾāreṣ gābar ḥasdô ʿal-yĕrēʾāyw</b> — <i>for as high as the heavens are above the earth, so great is his steadfast love for those who fear him</i>. The spatial metaphor for the immeasurable: the height of the heavens above the earth is the maximum visible distance (it cannot be measured from below). <i>Gābar</i> (to be mighty, prevail — the divine ḥesed is mighty, prevailing in measure). The comparison with the immeasurable does not quantify the ḥesed — it declares it beyond quantification.</p>",
    "12": "<p><b>kirhōq mizrāḥ mimmāʿărab hirḥîq mimmennû ʾet-pĕshāʿênû</b> — <i>as far as east is from west, that is how far he has removed our transgressions from us</i>. The east-west axis is directional, not circular: north and south eventually meet (one could travel far enough north to arrive in the south), but east and west never meet — one can travel east forever without arriving west. The infinite distance in the east-west direction is the image for the complete removal of transgressions (<i>pĕshāʿîm</i>: willful rebellious acts). <i>Hirḥîq</i> (hiphil: to remove to a distance — to place far away).</p>",
    "13": "<p><b>kĕraḥēm ʾāb ʿal-bānîm rāḥam YHWH ʿal-yĕrēʾāyw</b> — <i>just as a father is tender toward his children, so the LORD is tender toward those who fear him</i>. <i>Rāḥam</i> (piel: to show deep compassion — from <i>reḥem</i>: the womb). The father's compassion for his children as the analogy for divine compassion — not the womb-compassion of a mother (though that imagery also appears in Isa 49:15) but the protective, tender compassion of a father. The familial metaphor for divine-human relationship grounding the forgiveness of vv9-12.</p>",
    "14": "<p><b>kî-hûʾ yādaʿ yiṣrênû zākhûr kî-ʿāphār ʾănaḥnû</b> — <i>for he knows exactly what we are made of; he has not forgotten that we are dust</i>. <i>Yāṣar</i> (to form, shape — the potter's word; YHWH knows our formation because he formed us, Gen 2:7). <i>Zākhûr</i> (a passive participle: he is one who remembers — the ongoing divine awareness). <i>ʿĀphār</i> (dust — from Gen 2:7: <i>wayyîṣer YHWH ʾĕlōhîm ʾet-hāʾādām ʿāphār min-hāʾădāmāh</i>; and Gen 3:19: <i>ʿāphār ʾattāh wĕʾel-ʿāphār tāshûb</i>). The divine compassion (v13) grounded in the divine knowledge of human frailty: God's mercy is not naïve but precisely calibrated to what we actually are.</p>",
    "15": "<p><b>ʾĕnôsh kĕḥāṣîr yāmāyw kĕṣîṣ haśśādeh kēn yāṣîṣ</b> — <i>as for mortals, their days are like grass; they bloom like a wildflower of the field</i>. <i>ʾĔnôsh</i> (mortal man — the word emphasizing human frailty, from a root meaning to be sick/weak; contrast with <i>ʾādām</i> or <i>ʾîsh</i>). <i>Ḥāṣîr</i> (grass — cf. Ps 90:5-6; Isa 40:6-8). <i>Ṣîṣ haśśādeh</i> (wildflower of the field — the seasonal flower of the Palestinian landscape, beautiful and brief). The grass and wildflower together represent beauty + transience.</p>",
    "16": "<p><b>kî rûaḥ ʿābĕrāh-bô wĕʾênennû</b> — <i>the wind sweeps over it and it vanishes</i>. <i>Rûaḥ</i> (wind — here the hot sirocco that desiccates vegetation rapidly). <i>ʿĀbar</i> (to pass over — the wind's passage is enough to kill the grass). <b>wĕlōʾ-yakkîrennû ʿôd mĕqômô</b> — <i>and the place where it stood no longer knows it</i>. The personification of <i>māqôm</i> (place): the place no longer recognizes the person who stood there. The completeness of mortality — not just the person disappears but their location forgets them. Compare with the permanence of divine ḥesed in the next verse.</p>",
    "17": "<p><b>wĕḥesed YHWH mēʿôlām wĕʿad-ʿôlām ʿal-yĕrēʾāyw</b> — <i>but the steadfast love of the LORD is from age to age over those who fear him</i>. The pivot: the brevity of human life (vv15-16) set against the eternal divine ḥesed. <i>Mēʿôlām wĕʿad-ʿôlām</i> (from age to age — from everlasting to everlasting): the temporal scope of ḥesed is the exact opposite of human transience. <b>wĕṣidqātô libnê bānîm</b> — <i>and his righteousness reaches to their grandchildren</i>. The divine righteousness reaching to generations (<i>bĕnê bānîm</i>: sons of sons/grandchildren) — the covenantal faithfulness that outlasts individual lives and passes through family lines.</p>",
    "18": "<p><b>lĕshōmĕrê bĕrîtô ûlĕzōkhĕrê phiqquddāyw laʿăśôtām</b> — <i>to those who hold to his covenant and keep his commands in mind to live by them</i>. The two conditions defining those who receive the eternal ḥesed: <i>shāmar bĕrît</i> (keeping the covenant — the active maintenance of covenant relationship) + <i>zākar phiqqûdîm laʿăśôt</i> (remembering commands in order to do them — the doing as the purpose of the remembering). The ethical and relational dimensions together: covenant identity + obedient action.</p>",
    "19": "<p><b>YHWH bashshāmayim hēkhîn kissĕʾô ûmalkûtô bakkōl māshālāh</b> — <i>the LORD has set up his throne in the heavens; his kingdom governs everything that exists</i>. <i>Kûn</i> (hiphil perfect: he has established firmly — the divine throne is already established, not being established). <i>Malkût</i> (kingdom, sovereignty) governing <i>bakkōl</i> (over everything — the universal scope). The theological climax: before calling on the cosmic community to praise (vv20-22), the basis is stated — YHWH's universal sovereignty. Every created entity called to bless is within his governance.</p>",
    "20": "<p><b>bārekû YHWH malʾākhāyw gibbōrê kōaḥ</b> — <i>bless the LORD, you his angels — his mighty warriors</i>. The outward expansion of blessing: from the single soul (<i>nafshî</i>, vv1-2) now to the angels (<i>malʾākhîm</i>: messengers, divine council members). <i>Gibbōrê kōaḥ</i> (mighty in strength — the angels as powerful beings, cf. Ps 29:1's <i>bĕnê ʾēlîm</i>). <b>ʿōśê dĕbārô lishmoaʿ bĕqôl dĕbārô</b> — <i>who carry out his commands, swift to obey his voice</i>. <i>ʿĀśāh dābār</i> (to carry out his word/command) — obedience as the defining activity of the angels. <i>Lishmoaʿ bĕqôl dĕbārô</i> (to hear/obey the voice of his word) — hearing as the prelude to obedience.</p>",
    "21": "<p><b>bārekû YHWH kol-ṣĕbāʾāyw mĕshārĕtāyw ʿōśê rĕṣônô</b> — <i>bless the LORD, all his armies — all who serve him and carry out his purposes!</i> <i>Ṣĕbāʾîm</i> (armies, hosts — the divine armies of heaven, giving YHWH his title <i>ʾĕlōhê ṣĕbāʾôt</i>: God of hosts). <i>Mĕshārĕtāyw</i> (his servants/ministers — those who serve in the divine court). <i>Rāṣôn</i> (his pleasure, will, purpose) done: the angels carry out divine purposes rather than their own. The second circle of blessing: the angelic armies.</p>",
    "22": "<p><b>bārekû YHWH kol-maʿăśāyw bĕkhol-mĕqōmôt memshaltô</b> — <i>bless the LORD, everything he has made, in every place his reign extends</i>. The third circle: all of creation (<i>kol-maʿăśāyw</i>: all his works) in every place his dominion extends. The universal blessing of the Creator by all his creatures — the creation-wide doxology. <b>bārekî nafshî ʾet-YHWH</b> — <i>bless the LORD, O my soul!</i> The return to v1: the psalm that expanded from one soul to all creation returns to the single soul. The cosmic praise collapses back into the individual's personal blessing — showing that the single soul's praise participates in and echoes the cosmic praise of all creation.</p>"
  },
  "104": {
    "1": "<p><b>bārekî nafshî ʾet-YHWH YHWH ʾĕlōhay gādaltā mĕʾōd</b> — <i>bless the LORD, O my soul! O LORD my God, how great you are</i>. The self-address of Ps 103:1 opens the creation hymn. <i>Gādaltā mĕʾōd</i> (you are very great — the exclamatory recognition of divine greatness in the face of creation's scope). <b>hôd wĕhādār lābāshtā</b> — <i>robed in honor and majesty</i>. <i>Hôd</i> (splendor, majesty — the radiant glory of the divine presence) + <i>hādār</i> (honor, ornamental beauty). The divine Creator clothed in the qualities of creation's own beauty.</p>",
    "2": "<p><b>ʿōṭeh-ʾôr kaśśalmāh</b> — <i>wrapped in light as in a robe</i>. Light is not created (as in Gen 1:3 where it is the first created thing) but worn as a garment — the divine self-clothing in light precedes creation. The light is the outward expression of the divine glory, the garment that makes YHWH visible. <b>nôṭeh shāmayim kayyĕrîʿāh</b> — <i>spreading out the heavens like a tent curtain</i>. <i>Yĕrîʿāh</i> (tent curtain — the fabric panels of a tent). The heavens stretched like tent fabric by the divine hand — the image of a powerful deity pitching a cosmic tent (cf. Isa 40:22: <i>hantôṭeh kaddôq shāmayim</i>).</p>",
    "3": "<p><b>hameqāreh bammayim ʿăliyyôtāyw</b> — <i>he sets the beams of his upper chambers on the waters</i>. <i>Qārāh</i> (to set beams — the laying of the ceiling beams of a building) on the waters above the firmament (Gen 1:7's waters above). The divine palace above the heavenly waters — the upper rooms (<i>ʿăliyyôt</i>) of the cosmic palace. <b>haśśām ʿābîm rĕkhûbô hamehallek ʿal-kanpê-rûaḥ</b> — <i>he mounts the clouds as his chariot; he travels on the wings of the wind</i>. <i>ʿĀb</i> (thick cloud) as divine chariot — the storm-cloud as the vehicle of the divine warrior (cf. Ps 68:4, 33; Isa 19:1). <i>Kanpê-rûaḥ</i> (wings of the wind) — the wind as the speed of divine movement.</p>",
    "4": "<p><b>ʿōśeh malʾākhāyw rûḥôt mĕshārĕtāyw ʾēsh lōhēṭ</b> — <i>he makes the winds his messengers and flashing fire his servants</i>. The deliberate ambiguity: <i>malʾākhāyw rûḥôt</i> can be read as either (a) he makes his angels into winds (the angels are the winds) or (b) he makes the winds his messengers/angels. Both readings are grammatically valid. Heb 1:7 reads this in sense (a) — angels as winds — applying it to the Son's superiority over angels. The psalm's point in either case: the natural forces (wind, fire) are divine servants, not independent powers or deities.</p>",
    "5": "<p><b>yāsad-ʾereṣ ʿal-mĕkhônêhā</b> — <i>he fixed the earth on its foundations</i>. <i>Yāsad</i> (to found, lay the foundation — the architect's act of establishing the base). <i>Mĕkhôn</i> (foundation, established base — from kûn: to be fixed). <b>bal-timmôṭ ʿôlām wāʿed</b> — <i>so that it will never be shaken</i>. <i>Mûṭ</i> (to shake, totter — the destabilization of what is fixed). The double temporal scope: <i>ʿôlām wāʿed</i> (forever and ever). The earth's stability as a consequence of divine founding — it holds because of the divine action that established it.</p>",
    "6": "<p><b>tĕhôm kallib-bûsh kissîtô</b> — <i>you covered it with the deep like a cloak</i>. <i>Tĕhôm</i> (the deep — the primordial ocean of Gen 1:2; the deep that covered the pre-creation earth). <i>Libûsh</i> (clothing, garment) — the deep draped over the earth like a cloak (echoing the divine light-clothing of v2: YHWH wears light; the earth is clothed in the deep). <b>ʿal-hārîm yaʿamdû māyim</b> — <i>the waters towered above the mountains</i>. The primordial state: waters covering even the mountain peaks — the pre-creation condition before the divine ordering of v7-9.</p>",
    "7": "<p><b>min-gĕʿārātĕkhā yānûsûn</b> — <i>at your rebuke they retreated</i>. <i>Gāʿar</i> (to rebuke — the commanding voice that drives away; cf. Ps 106:9 where the sea is rebuked at the Exodus). The waters flee at the divine rebuke — the chaos-ordering by divine voice. <b>min-qôl raʿamĕkhā yēḥāpēzûn</b> — <i>at the sound of your thunder they fled in haste</i>. <i>Raʿam</i> (thunder — the divine voice in the storm) causing the waters to flee in terror (<i>ḥāpaz</i>: to be in hasty flight). The creation of order is described in the language of a theophany — the storm-God commanding the chaotic waters.</p>",
    "8": "<p><b>yaʿălû hārîm yērĕdû bĕqāʿôt ʾel-mĕqôm zeh yāsadtā lāhem</b> — <i>the mountains rose and the valleys sank to the places you had set for them</i>. The topographic ordering: mountains rising, valleys descending — the creation of the varied landscape. <i>Mĕqôm zeh yāsadtā lāhem</i> (the place you founded for them) — each geological feature placed exactly where YHWH designed it. The creative act as precise architectural intentionality.</p>",
    "9": "<p><b>gĕbûl śamtā bal-yaʿăbōrûn</b> — <i>you drew a boundary they cannot cross</i>. <i>Gĕbûl</i> (boundary, border — the territorial limit set by divine decree) + <i>lōʾ yaʿăbōrûn</i> (they shall not cross it — the permanent prohibition on the chaos-waters). <b>bal-yĕkhassûn lĕkhassôt hāʾāreṣ</b> — <i>so the waters will never again engulf the earth</i>. The covenant promise echoing the Noahic covenant (Gen 9:11-15): the waters will not again cover the earth. The creation-order is protected by divine decree — the chaos does not simply retreat but is permanently bounded.</p>",
    "10": "<p><b>hamekhallēaḥ maʿyānîm bannĕḥālîm</b> — <i>he sends springs into the valleys</i>. The transition from creation's ordering (vv5-9) to creation's provision (vv10-18): water in the right place (springs in valleys, not covering mountains) becomes the source of life. <i>Maʿyān</i> (spring of water) sent into <i>nĕḥālîm</i> (valleys, wadis — the dry riverbeds that fill with spring water). <b>bên hārîm yĕhallēkhûn</b> — <i>they run between the hills</i>. The springs becoming streams flowing through the hill country — the water system threading through the created landscape.</p>",
    "11": "<p><b>yashqû kol-ḥaytô śādāy</b> — <i>giving water to every wild animal</i>. <i>Shāqāh</i> (to water, give drink) — the springs providing water to all the wild animals. <b>yishbĕrû pĕrāʾîm ṣĕmāʾām</b> — <i>the wild donkeys slake their thirst there</i>. <i>Pereh</i> (wild donkey/onager — the untameable wild ass of the open steppe; Job 39:5-8 describes its freedom). The wild, uncatchable creature finds its thirst quenched by the Creator's springs — even the wildest animals are provided for.</p>",
    "12": "<p><b>ʿălêhem ʿôph hashshāmayim yishkôn</b> — <i>along their banks the birds of the sky make their homes</i>. <i>Shākan</i> (to dwell, tabernacle — the verb of the divine dwelling among Israel; here the birds of the sky dwelling along the streams). <b>mibbên ʿŏphāyim yittĕnû-qôl</b> — <i>and sing among the branches</i>. The birdsong among the branches (<i>ʿŏphāyim</i>: branches, foliage) as part of the created order's praise — the birds' song as creation's voice.</p>",
    "13": "<p><b>mashqeh hārîm mēʿăliyyôtāyw</b> — <i>from his upper chambers he sends rain down the mountains</i>. <i>ʿĂliyyôt</i> (upper chambers — the same divine palace-rooms of v3 from which the cloud-chariot departs). The rain comes from the divine palace above the clouds — the water cycle as divine provision from the heavenly dwelling. <b>mippĕrî maʿăśêkhā tiśbaʿ hāʾāreṣ</b> — <i>the earth is filled by what he provides</i>. <i>Mippĕrî maʿăśêkhā</i> (from the fruit of your works) — the earth satisfied by the fruit of the divine creative activity. Creation's abundance is always the ongoing result of divine action, not an independent system.</p>",
    "14": "<p><b>maṣmîaḥ ḥāṣîr labbĕhēmāh wĕʿēśeb laʿăbōdat hāʾādām</b> — <i>he makes grass grow for the cattle and plants for people to tend</i>. <i>Ṣāmaḥ</i> (hiphil: to cause to sprout — the divine causation of vegetative growth). <i>Ḥāṣîr labbĕhēmāh</i> (grass for the cattle) + <i>ʿēśeb laʿăbōdat hāʾādām</i> (vegetation for the labor/service of humanity — the agricultural plants that human work cultivates). <b>lĕhôṣîʾ leḥem min-hāʾāreṣ</b> — <i>so they can bring food out of the ground</i>. The partnership: God causes growth, humans labor, bread comes from the ground. Divine and human action together in the provision of food.</p>",
    "15": "<p><b>wĕyayin yĕśammah lĕbab-ʾĕnôsh</b> — <i>wine that lifts the human heart</i>. <i>Śāmaḥ lēbāb</i> (to gladden the heart) — wine as a created good, explicitly approved by the Creator as something that produces the gladness of the human heart. <b>lĕhahălîl pānîm mishshāmen</b> — <i>oil that makes the face glow</i>. <i>Hālal pānîm</i> (to make the face shine — the radiant, health-full face) from the oil. <b>wĕleḥem lĕbab-ʾĕnôsh yisʿād</b> — <i>and bread that gives strength to the human heart</i>. <i>Sāʿad</i> (to support, sustain — bread as the fundamental support of the body and the heart). The three gifts (wine, oil, bread) represent the full range of agricultural provision — festive, cosmetic, and nutritive.</p>",
    "16": "<p><b>yiśbĕʿû ʿăṣê YHWH ʾarzê lĕbānôn ʾăsher nāṭāʿ</b> — <i>the trees of the LORD drink deeply — the great cedars of Lebanon that he himself planted</i>. <i>ʿĂṣê YHWH</i> (the trees of the LORD — trees belonging to YHWH by his planting) = the cedars of Lebanon (<i>ʾarzê lĕbānôn</i>). <i>Nāṭaʿ</i> (to plant — the divine planting of the great trees). The magnificent cedars are not self-seeded but divinely planted — God as the forester who planted the greatest trees on earth. They are <i>yiśbĕʿûn</i> (satisfied/well-watered) — provided for as YHWH provides for all living things.</p>",
    "17": "<p><b>ʾăsher shām ṣippārîm yĕqannēnû</b> — <i>there the birds build their nests</i>. The great cedars as habitat — the magnificent trees become the homes of the birds. <i>Qānan</i> (to build a nest — the nesting act). <b>ḥăsîdāh bĕrôshîm bêtāh</b> — <i>the stork finds her home in the cypress trees</i>. <i>Ḥăsîdāh</i> (the stork — from <i>ḥesed</i>: the stork known for its loyalty/devotion to its young; the bird named for covenant-love). <i>Bĕrôsh</i> (cypress or juniper). Even the stork — whose name carries the root of covenant loyalty — is provided for in the divinely-planted trees.</p>",
    "18": "<p><b>hārîm haggĕbōhîm layye-ʿēlîm</b> — <i>the rugged mountains belong to the wild goats</i>. <i>Yaʿēl</i> (mountain goat/ibex — the wild goat adapted to the steep rocky terrain). <b>sĕlāʿîm maḥseh lashshĕphannîm</b> — <i>the rocky crags shelter the rock badgers</i>. <i>Shāphān</i> (rock badger/hyrax — the small mammal that lives in rock crevices). The full range of habitats — tall cedars, mountains, rocky crags — each provided with its appropriate inhabitants. The ecosystems of creation as divine arrangement, not random distribution.</p>",
    "19": "<p><b>ʿāśāh yārēaḥ lĕmôʿădîm</b> — <i>he appointed the moon to mark the seasons</i>. <i>Môʿēd</i> (appointed time, season, festival — the calendar system). The moon created specifically for the purpose of marking the calendar (<i>lĕmôʿădîm</i>: for the appointed seasons). <b>shemesh yādaʿ mĕbôʾô</b> — <i>the sun knows exactly when to set</i>. <i>Yādaʿ mābôʾ</i> (knows its setting — the sun as an obedient servant that knows its time). Both luminaries created for their functions, not worshiped as deities — the radical demythologization of the astral powers in Israelite cosmology (cf. Gen 1:14-18 where they are named merely <i>greater light</i> and <i>lesser light</i>).</p>",
    "20": "<p><b>tāshēt ḥōshekh wayĕhî lāylāh</b> — <i>you bring on darkness and it becomes night</i>. The divine causing of night — YHWH as the one who sets (<i>shît</i>) the darkness into place. Night is not the absence of divine activity but a divinely appointed time. <b>bô-tirmōś kol-ḥaytô-yāʿar</b> — <i>when all the forest creatures stir</i>. <i>Rāmaś</i> (to creep, crawl, move about — especially of the smaller animals). The night as the time appointed for the forest animals' activity — the nocturnal ecosystem as part of the divine design.</p>",
    "21": "<p><b>hakkĕphîrîm shōʾăgîm lataref</b> — <i>the young lions roar as they hunt</i>. <i>Kĕphîr</i> (young lion — the lion in its prime hunting strength). <i>Shāʾag</i> (to roar — the hunting roar of the lion). <b>ûlĕbaqshēsh mēʾēl ʾākĕlām</b> — <i>looking to God for their food</i>. <i>Bāqash mēʾēl</i> (seeking from God) — even the lion's hunting is described as seeking food from God. The predator's hunger and the act of hunting are within the providential framework of the Creator's provision. Not a theological problem but a theological observation: the whole creation, including its predatory activity, is encompassed in divine providence.</p>",
    "22": "<p><b>tizraḥ hashshemesh yēʾāsēphûn</b> — <i>when the sun comes up, they slip away</i>. The transition at sunrise: the nocturnal hunters return to their lairs. <i>ʾāsaph</i> (niphal: to be gathered, to withdraw — the lions withdrawing as the sun rises). <b>wĕʾel-mĕʿônōtām yirĕbāṣûn</b> — <i>and stretch out in their lairs</i>. <i>Rābaṣ</i> (to crouch, lie down — the resting posture of an animal in its den). The daily rhythm of animal life governed by the sun's rising and setting — the clock set by the Creator in v19 regulates the whole ecosystem.</p>",
    "23": "<p><b>yēṣēʾ ʾādām lĕphōʿŏlô wĕlaʿăbōdātô ʿădê-ʿāreb</b> — <i>then people go out to their work and labor on until the evening</i>. <i>ʾĀdām</i> (humanity — the human sphere of activity). <i>Phōʿal</i> (work, labor) + <i>ʿăbōdāh</i> (service, labor — the human labor to which people go out at sunrise). The human labor-day framed within the same creation order that governs the lions' night — humans and lions share the same divinely ordered world, each active in its appointed time.</p>",
    "24": "<p><b>māh-rabbû maʿăśêkhā YHWH kullām bĕḥokhĕmāh ʿāśîtā</b> — <i>LORD, what a multitude of works you have made! You crafted them all in wisdom</i>. <i>Māh-rabbû</i> (how many! — the exclamatory response to creation's abundance). <i>Bĕḥokhĕmāh ʿāśîtā</i> (you made all of them in wisdom — <i>ḥokhĕmāh</i> as the divine design-principle behind creation; cf. Prov 8:22-31 where Wisdom is personified as present at creation). <b>māleʾāh hāʾāreṣ qinyanekā</b> — <i>the earth is full of what belongs to you</i>. <i>Qinyan</i> (acquisition, possession, creature — what God has acquired/created). The earth as YHWH's full possession.</p>",
    "25": "<p><b>zeh hayyām gādôl ûrĕḥab yādāyim</b> — <i>and here is the sea — vast and wide</i>. <i>Zeh</i> (this — the demonstrative pointing as if to say: look at that). <i>Gādôl ûrĕḥab yādāyim</i> (great and wide of hands/dimensions — the spatial immensity of the sea). <b>shām remes wĕʾên mispār ḥayyôt qĕṭannôt ʿim-gĕdōlôt</b> — <i>teeming with creatures beyond counting, great and small alike</i>. <i>Remes</i> (swarming, creeping things — the creatures that swarm in the sea). <i>ʾên mispār</i> (no counting — the innumerable abundance). Great and small together: the ecosystem's full range of scale.</p>",
    "26": "<p><b>shām ʾoniyyôt yĕhallēkhûn lĕwiyātān zeh-yāṣartā lĕśaḥeq-bô</b> — <i>the ships sail there, and there is Leviathan, which you formed to frolic in the deep</i>. <i>Lĕwiyātān</i> (Leviathan — the chaos dragon of Job 41, Ps 74:14, Isa 27:1; the sea-monster that represents primordial chaos in the ancient Near Eastern imagination). Here the psalm radically domesticates the chaos monster: <i>zeh-yāṣartā lĕśaḥeq-bô</i> (this one you formed to play in it). Leviathan is not an enemy to be defeated (as in Ps 74:14 or the Ugaritic Baal mythology) but a creature YHWH formed (<i>yāṣar</i>: the potter's forming) specifically to play (<i>śāḥaq</i>: to sport, play) in the sea. The most feared creature in ancient mythology becomes God's pet — the ultimate demythologization of chaos.</p>",
    "27": "<p><b>kullām ʾēlêkhā yĕśabbērûn lātēt ʾokhĕlām bĕʿittô</b> — <i>all of these look to you to give them their food when they need it</i>. <i>Śābar ʾēl</i> (to look/wait expectantly toward — the posture of patient expectation directed toward God). All the creatures of vv10-26 — wild donkeys, birds, storks, ibex, lions, sea creatures, Leviathan itself — all looking to YHWH for their food. <i>Bĕʿittô</i> (in its time — the providential timing of the divine provision). Creation is not self-sustaining but continuously dependent on the Creator.</p>",
    "28": "<p><b>tittēn lāhem yilqôṭûn tiphttaḥ yādĕkhā yiśbĕʿûn ṭôb</b> — <i>when you give, they gather it in; when you open your hand, they are satisfied with good</i>. <i>Yalqaṭ</i> (to gather — as grain is gathered from the field). <i>Pātaḥ yād</i> (to open the hand — the gesture of generous giving; cf. Ps 145:16: the divine open hand satisfying the desire of every living thing). <i>Śābaʿ ṭôb</i> (to be satisfied with good) — the same satisfaction sought in human prayer answered in the ongoing divine provision to all creatures.</p>",
    "29": "<p><b>tastîr pānêkhā yibbāhēlûn</b> — <i>if you hide your face, they are terrified</i>. <i>Sātar pānim</i> (to hide the face — the divine withdrawal of attention and favor; cf. Ps 88:14; 102:2). When the divine face is hidden, the creatures are terrified (<i>bāhal</i>: to be dismayed, thrown into panic). <b>tōsēph rûḥām yigwāʿûn wĕʾel-ʿăphārām yāshûbûn</b> — <i>if you take back their breath, they die and return to dust</i>. <i>Rûaḥ</i> (breath, spirit) given or taken by God — the divine in-breathing and out-taking as the generator and terminator of life. <i>ʿĂphār</i> (dust — returning to Gen 3:19's dust). The Creator's breath sustains; its withdrawal ends.</p>",
    "30": "<p><b>tishlaḥ rûḥăkhā yibbārēʾûn ûtĕḥaddēsh pĕnê ʾădāmāh</b> — <i>when you send out your Spirit, they are created, and you renew the surface of the earth</i>. <i>Shālaḥ rûaḥ</i> (to send out the Spirit/breath) + <i>bārāʾ</i> (to create — the Genesis 1 creation verb). The continuous creation: YHWH sending out his Spirit continually creates new life. <i>Tĕḥaddēsh pĕnê ʾădāmāh</i> (you renew the face of the earth) — the renewal of the created surface. The Spirit of Gen 1:2 (<i>rûaḥ ʾĕlōhîm mĕraḥephet ʿal-pĕnê hammāyim</i>) as the ongoing creative force in creation, not merely a past event.</p>",
    "31": "<p><b>yĕhî khĕbôd YHWH lĕʿôlām yiśmaḥ YHWH bĕmaʿăśāyw</b> — <i>may the glory of the LORD last forever; may the LORD take delight in what he has made!</i> <i>Kĕbôd YHWH lĕʿôlām</i> (the glory of YHWH forever) — the prayer that the divine glory, the weight and presence of God, endure eternally. <i>Yiśmaḥ YHWH bĕmaʿăśāyw</i> (may YHWH take delight/rejoice in his works) — echoing Gen 1:31 (<i>wayyarʾ ʾĕlōhîm ʾet-kol-ʾăsher ʿāśāh wĕhinnēh ṭôb mĕʾōd</i>: God saw all he had made and it was very good). The petition that the divine delight in creation continue — a relational prayer asking that the Creator-creature relationship of pleasure persist.</p>",
    "32": "<p><b>hammaббîṭ lāʾāreṣ wattirʿad yiggaʿ bĕhārîm wĕyeʿĕshānû</b> — <i>he looks at the earth and it shakes; he touches the mountains and they pour out smoke</i>. The theophanic power: divine looking causes earthquakes; divine touching causes volcanic eruption. The same power that ordered creation (vv5-9) can unmake its structures with a glance. The Creator's power over creation is not merely historical but perpetual and immediate.</p>",
    "33": "<p><b>ʾāshîrāh laYHWH bĕḥayyāy ʾăzammĕrāh lĕʾĕlōhay bĕʿôdî</b> — <i>I will sing to the LORD as long as I live; I will sing praise to my God for as long as I draw breath</i>. <i>Bĕḥayyāy</i> (while I live — the full span of the Psalmist's life dedicated to praise). <i>Bĕʿôdî</i> (while I yet am — while I exist, while there is still breath). The personal vow: the lifetime of the individual Psalmist devoted to singing and praise. The cosmic creation hymn narrows at the end to the single human voice committed to praise for life.</p>",
    "34": "<p><b>yĕʿerab ʿālāyw śîḥî ʾānōkhî ʾeśmaḥ baYHWH</b> — <i>may my thoughts about him be sweet to him, as I find my joy in the LORD</i>. <i>ʿĀrēb</i> (to be sweet, pleasing — the flavor-word for something delightful). <i>Śîaḥ</i> (meditation, reflection — the murmured meditation of Ps 77:3, 6; 104:34). The prayer that the Psalmist's meditation be pleasing (<i>ʿārēb</i>) to YHWH — the inner life offered as an acceptable offering. <i>ʾĔśmaḥ baYHWH</i> (I will rejoice in the LORD) — the personal joy grounded in the Creator who has just been celebrated across 33 verses.</p>",
    "35": "<p><b>yittammû ḥaṭṭāʾîm min-hāʾāreṣ ûrĕshāʿîm ʿôd ʾênam</b> — <i>let sinners vanish from the earth and let the wicked exist no longer!</i> The jarring petition at the creation hymn's end — the one discordant note in the celebration of created order. Sinners (<i>ḥaṭṭāʾîm</i>) and the wicked (<i>rĕshāʿîm</i>) are the creatures who mar what has been celebrated as beautiful and good. The prayer for their removal is not vindictive but ecological — creation's perfection requires the removal of those who desecrate it. <b>bārekî nafshî ʾet-YHWH hallĕlûyāh</b> — <i>bless the LORD, O my soul! Hallelujah!</i> The return to the opening self-address (as in Ps 103:22) and the first <i>hallĕlûyāh</i> (praise-YHWH) in the Psalter — a compound formed from <i>hallelû</i> (praise ye!) + <i>YAH</i> (the abbreviated divine name). The creation hymn ends with the first hallelujah, launching the hallelujah psalms that increasingly dominate Psalms 105-150.</p>"
  }
}

def main():
    data = load_comm('mkt-original', 'psalms')
    merge_comm(data, NEW)
    save_comm('mkt-original', 'psalms', data)
    for ch in ['103', '104']:
        vcount = len(data.get(ch, {}))
        print(f'  Ps {ch}: {vcount} verses')

if __name__ == '__main__':
    main()
